import { useState, useRef } from 'react'
import style from './style.module.css'
// import introVideo from './../assets/media/curtain_video.mp4'
import introVideo from './../assets/media/envelop_video.mp4'

function IntroSlide() {

    const videoRef = useRef()
    // const [showContent, setShowContent] = useState(true)
    const [showContent, setShowContent] = useState(false)

    // const handleVideoClick = () => {
    //     const video = videoRef.current;
    //     if (video) {
    //         if (video.paused) {
    //             video.play()
    //             setTimeout(() => setShowContent(true), 2000)
                
    //         }
    //     }
    // }

    return (
        <>
            <div className={style.introContainer}>
                <div>
                    <p className={style.title}>We're getting married</p>

                    <h1 className={style.names}>
                        <span>Ahmed</span>
                        <span>&</span>
                        <span>Nehal</span>
                    </h1>
                </div>

                <div>
                    <div className={style.divider}>
                        <span></span>
                        <span>✦</span>
                        <span></span>
                    </div>

                    <p className={style.date}>9 April 2026</p>
                    <p className={style.time}>08:00 PM</p>

                    <p className={style.details}>Details</p>

                    <div className={style.scrollArrow}>
                        <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                            <path d="m6 9 6 6 6-6"></path>
                        </svg>
                    </div>
                </div>
            </div>

            <div className={style.overlay}></div>

            <button 
                className={[style.startBtn, showContent && style.hideStartBtn].join(' ')}
                onClick={() => setShowContent(true)}
            >
            </button>
        </>
    )
}

export default IntroSlide
